package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    void setUp() throws Exception {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);

        // Use reflection to find and invoke the private constructor
        var constructors = DefaultDateTypeAdapter.class.getDeclaredConstructors();
        var constructor = constructors[0]; // pick the first constructor (DateType<T>, String)
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateTypeMock, "yyyy-MM-dd");
    }

    @Test
    void read_NullToken_ReturnsNull() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        doNothing().when(jsonReader).nextNull();

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void read_ValidDate_DeserializeCalled() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        Date expectedDate = new Date();
        Date expectedDeserialized = new Date();

        // Use reflection to set the private dateFormats list to contain a DateFormat that returns expectedDate
        // Instead, we will spy on adapter and stub deserializeToDate via reflection of the private method

        // Create spy
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        // Use reflection to get the private method deserializeToDate
        var method = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        method.setAccessible(true);

        // Instead of mocking the private method (which is private and final),
        // we override it by using doAnswer on spyAdapter.read to call the real method but substitute deserializeToDate

        // We cannot mock private method directly, so we override read to call our own deserializeToDate via reflection

        // To simulate deserializeToDate returning expectedDate, we create a subclass that overrides deserializeToDate
        DefaultDateTypeAdapter<Date> adapterWithOverride = new DefaultDateTypeAdapter<Date>(dateTypeMock, "yyyy-MM-dd") {
            @Override
            @SuppressWarnings("unchecked")
            protected Date deserializeToDate(JsonReader in) {
                return expectedDate;
            }
        };

        // Spy on this subclass
        DefaultDateTypeAdapter<Date> spyAdapter2 = Mockito.spy(adapterWithOverride);

        when(dateTypeMock.deserialize(expectedDate)).thenReturn(expectedDeserialized);

        Date result = spyAdapter2.read(jsonReader);

        verify(jsonReader).peek();
        verify(dateTypeMock).deserialize(expectedDate);
        assertEquals(expectedDeserialized, result);
    }
}
